code.C:
#include <stdio.h>
#include <assert.h>

int main() {
    int n, m;
    scanf("%d %d", &n, &m);

    assert(1 <= n && n <= 100);
    assert(1 <= m && m <= 100);

    int mat[n][m];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            scanf("%d", &mat[i][j]);
        }
    }

    for (int i = 0; i < n; i++) {
        if (i % 2 == 0) {
            for (int j = 0; j < m; j++) {
                printf("%d ", mat[i][j]);
            }
        } else {
            for (int j = m - 1; j >= 0; j--) {
                printf("%d ", mat[i][j]);
            }
        }
    }

    return 0;
}

